module RefModule(
    input [7:0] current_pixel,
    input [7:0] previous_pixel,
    output [7:0] filtered_pixel
);
    wire __current_pixel_tmp = (current_pixel >= previous_pixel);
    assign filtered_pixel = __current_pixel_tmp ? (current_pixel - previous_pixel) : (current_pixel + 256 - previous_pixel);
endmodule
